const GABARITO_SALDO    = 26509620.12;
const GABARITO_AGENCIAS = 10;
const TOLERANCIA        = 0.10;

const rows = $input.all();
const totalSaldo  = rows.reduce((s, r) => s + parseFloat(r.json.saldo_total || 0), 0);
const qtdAgencias = rows.length;
const diferenca   = Math.abs(totalSaldo - GABARITO_SALDO);
const aprovado    = diferenca <= TOLERANCIA && qtdAgencias === GABARITO_AGENCIAS;

return [{
  json: {
    kpi:             'KPI1',
    status:          aprovado ? 'APROVADO' : `FALHOU (dif=${diferenca.toFixed(4)})`,
    aprovado,
    saldo_calculado: totalSaldo.toFixed(2),
    saldo_gabarito:  GABARITO_SALDO.toFixed(2),
    qtd_agencias:    qtdAgencias
  }
}];

// Consolida resultados de todos os KPIs e gera resumo final
const kpi1 = $('Validar KPI1').first().json;

const kpis = [
  { kpi: 'KPI1', status: kpi1.status },
  { kpi: 'KPI2', status: 'CALCULADO' },
  { kpi: 'KPI4', status: 'CALCULADO' },
  { kpi: 'KPI7', status: 'CALCULADO' },
];

const linhas = kpis.map(k => {
  const ok = k.status === 'APROVADO' || k.status === 'CALCULADO';
  return `  [${ok ? 'OK' : '!!'}] ${k.kpi}: ${k.status}`;
});

const resumo = [
  '='.repeat(50),
  '  BanVic 360 - Projeto 8 (n8n) - Resultado',
  '='.repeat(50),
  ...linhas,
  '='.repeat(50),
  `  Gabarito KPI1: R$ 26.509.620,12 | 10 agencias`,
  `  Calculado KPI1: R$ ${kpi1.saldo_calculado}`,
].join('\n');

console.log(resumo);

return [{
  json: {
    resumo,
    kpi1_status:  kpi1.status,
    kpi1_saldo:   kpi1.saldo_calculado,
    todos_ok:     kpi1.aprovado,
    timestamp:    new Date().toISOString()
  }
}];
